// 19:30 쿠팡/Sheet pending backfill 후보 산출
// 기본: 전일 포함 최근 3개 확정일 daily_sales를 항상 점검한다.
// - NocoDB 행이 없으면 F23으로 재집계한다.
// - 쿠팡 수집 상태가 pending/api_error/skipped 이거나,
// - Google Sheet C:G가 NocoDB 자동채널 값과 비어 있거나 불일치하면 F23으로 재집계한다.
// 수동 웹훅 body.dates 또는 body.targetDate가 있으면 해당 날짜만 강제 후보로 사용한다.
let body = {};
let isWebhook = false;
try {
  body = $('수동 백필').first().json.body || {};
  isWebhook = true;
} catch (e) {}
const token = String($env.NOCODB_TOKEN || '').trim();
const baseUrl = 'https://nocodb.pressco21.com/api/v1/db/data/noco/pbmo0os7rnvfd48/mwxvxjiqtw177xu';
const chatId = String(body.chatId || body.chat_id || '-5251214343');
const explicitDates = Array.isArray(body.dates) ? [...body.dates] : [];
if (body.targetDate || body.target_date) explicitDates.push(body.targetDate || body.target_date);
const isDate = (value) => /^\d{4}-\d{2}-\d{2}$/.test(String(value || ''));
const unique = (list) => [...new Set(list.filter(isDate).map(String))].sort();
const makeItem = (json) => ({ json: { ...json, chatId, isWebhook } });

let sheetRows = [];
let sheetReadError = '';
try {
  const sheetResp = $('올해 Sheet 일별 매출 조회').first().json || {};
  if (sheetResp.error || sheetResp.message) {
    sheetReadError = String(sheetResp.error || sheetResp.message).slice(0, 300);
  } else {
    sheetRows = Array.isArray(sheetResp.values) ? sheetResp.values : [];
  }
} catch (e) {
  sheetReadError = e.message;
}

const num = (v) => {
  if (v === undefined || v === null || v === '') return 0;
  return parseInt(String(v).replace(/[^0-9.-]/g, '')) || 0;
};
const sheetIndexForDate = (dt) => {
  const parts = String(dt).split('-').map(Number);
  const target = new Date(Date.UTC(parts[0], parts[1] - 1, parts[2]));
  const jan1 = new Date(Date.UTC(parts[0], 0, 1));
  return Math.round((target - jan1) / 86400000);
};
const sheetValuesForDate = (dt) => {
  if (sheetReadError) return [];
  const sheetRow = sheetRows[sheetIndexForDate(dt)] || [];
  return [0, 1, 2, 3, 4].map((idx) => num(sheetRow[idx]));
};
const sheetCompare = (row) => {
  if (sheetReadError) return { ok: true, reason: '', sheetValues: [] };
  const dt = String(row.report_date || '').slice(0, 10);
  const sheetValues = sheetValuesForDate(dt);
  const expected = [
    num(row.makeshop_revenue),
    num(row.naver_revenue),
    num(row.st11_revenue),
    num(row.crm_revenue),
    num(row.coupang_revenue),
  ];
  const expectedHasValue = expected.some((value) => value !== 0);
  const sheetHasValue = sheetValues.some((value) => value !== 0);
  if (expectedHasValue && !sheetHasValue) return { ok: false, reason: 'sheet_missing', sheetValues, expected };
  for (let i = 0; i < expected.length; i++) {
    if (sheetValues[i] !== expected[i]) return { ok: false, reason: 'sheet_mismatch', sheetValues, expected };
  }
  return { ok: true, reason: '', sheetValues, expected };
};

if (unique(explicitDates).length > 0) {
  return unique(explicitDates).map((targetDate) => makeItem({ targetDate, reason: 'manual', skip: false, sheetReadError }));
}

if (!token) {
  return [makeItem({ skip: true, reason: 'NOCODB_TOKEN 미설정', sheetReadError })];
}

const now = new Date(Date.now() + 9 * 60 * 60 * 1000);
// F23/F24 확정 리포트 기준은 전일 이전이다. 당일 row는 부분 집계가 될 수 있어 자동 backfill에서 제외한다.
const endDate = new Date(now);
endDate.setDate(endDate.getDate() - 1);
const lookbackDays = 3;
const targetDates = [];
for (let offset = lookbackDays - 1; offset >= 0; offset--) {
  const d = new Date(endDate);
  d.setDate(endDate.getDate() - offset);
  targetDates.push(d.toISOString().slice(0, 10));
}
const start = targetDates[0];
const end = targetDates[targetDates.length - 1];

try {
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: baseUrl,
    headers: { 'xc-token': token },
    qs: {
      where: '(report_date,gte,' + start + ')~and(report_date,lte,' + end + ')',
      sort: '-report_date,-Id',
      limit: 100,
      fields: 'Id,report_date,makeshop_revenue,naver_revenue,st11_revenue,crm_revenue,coupang_revenue,coupang_orders,total_revenue,total_orders,coupang_collection_status,notes'
    }
  });
  const latestByDate = {};
  for (const row of (resp.list || [])) {
    const dt = String(row.report_date || '').slice(0, 10);
    if (!isDate(dt)) continue;
    if (!latestByDate[dt] || (parseInt(row.Id) || 0) > (parseInt(latestByDate[dt].Id) || 0)) latestByDate[dt] = row;
  }
  const candidates = [];
  for (const dt of targetDates) {
    const row = latestByDate[dt];
    if (!row) {
      candidates.push(makeItem({
        targetDate: dt,
        reason: 'missing_nocodb_record',
        skip: false,
        sheetReadError,
        sheetValues: sheetValuesForDate(dt),
        expectedSheetValues: [],
        beforeTotalRevenue: null,
        beforeTotalOrders: null,
        beforeCoupangRevenue: null,
        beforeCoupangOrders: null,
      }));
      continue;
    }
    const notes = String(row.notes || '').toLowerCase();
    const collectionStatus = String(row.coupang_collection_status || '').toLowerCase();
    const coupangRevenue = num(row.coupang_revenue);
    const coupangOrders = num(row.coupang_orders);
    const statusNeedsBackfill = /pending|api_error|skipped_blackout|sheet_existing/.test(collectionStatus);
    const hasPendingNote = /pending|blackout|403|429|timeout|휴지시간|추후/.test(notes) && /coupang|쿠팡/.test(notes);
    const totalRevenue = num(row.total_revenue);
    const legacyEmptyCoupang = !collectionStatus && totalRevenue > 0 && coupangRevenue === 0 && coupangOrders === 0 && /coupang|쿠팡|pending|blackout|403|429|timeout|휴지시간|추후/.test(notes);
    const sheetState = sheetCompare(row);
    if (statusNeedsBackfill || hasPendingNote || legacyEmptyCoupang || !sheetState.ok) {
      const reason = statusNeedsBackfill
        ? 'status_' + collectionStatus
        : (hasPendingNote ? 'note_pending' : (legacyEmptyCoupang ? 'legacy_empty_coupang' : sheetState.reason));
      candidates.push(makeItem({
        targetDate: dt,
        recordId: row.Id,
        reason,
        skip: false,
        sheetReadError,
        sheetValues: sheetState.sheetValues,
        expectedSheetValues: sheetState.expected,
        beforeTotalRevenue: totalRevenue,
        beforeTotalOrders: num(row.total_orders),
        beforeCoupangRevenue: coupangRevenue,
        beforeCoupangOrders: coupangOrders,
      }));
    }
  }
  if (candidates.length) return candidates;
  const reason = sheetReadError ? 'Sheet 조회 실패: ' + sheetReadError : '최근 3일 백필 후보 없음';
  return [makeItem({ skip: true, reason, start, end, checkedDates: targetDates, sheetReadError })];
} catch (e) {
  return [makeItem({ skip: true, reason: '최근 3일 후보 조회 실패: ' + e.message, start, end, checkedDates: targetDates, sheetReadError })];
}

const items = $input.all().map((item) => item.json || {});
let isWebhook = false;
try {
  $('수동 백필').first().json;
  isWebhook = true;
} catch (e) {}

let sourceCandidates = [];
try {
  sourceCandidates = $('백필 대상 계산').all().map((item) => item.json || {});
} catch (e) {}
const candidateByDate = {};
for (const candidate of sourceCandidates) {
  const dt = candidate.targetDate || candidate.date || candidate.report_date;
  if (dt) candidateByDate[String(dt).slice(0, 10)] = candidate;
}

const skipped = items.filter((row) => row.skip);
const executed = items.filter((row) => !row.skip);
const sheetReadError = items.find((row) => row.sheetReadError)?.sheetReadError || '';

const parseMaybeJson = (value) => {
  if (typeof value !== 'string') return value || {};
  try { return JSON.parse(value); } catch (e) { return {}; }
};
const num = (value) => {
  if (value === undefined || value === null || value === '') return 0;
  return parseInt(String(value).replace(/[^0-9.-]/g, '')) || 0;
};
const hasNumber = (value) => value !== undefined && value !== null && value !== '';
const fmt = (value) => num(value).toLocaleString('ko-KR') + '원';
const signedFmt = (value) => {
  const n = num(value);
  if (n === 0) return '변동 없음';
  return (n > 0 ? '+' : '-') + Math.abs(n).toLocaleString('ko-KR') + '원';
};
const statusOf = (row) => parseMaybeJson(row.status);
const coupangOf = (row) => parseMaybeJson(statusOf(row).coupang || row.coupang);
const nocodbOf = (row) => parseMaybeJson(statusOf(row).nocodb || row.nocodb);
const sheetsOf = (row) => parseMaybeJson(statusOf(row).sheets || row.sheets);
const channelsOf = (row) => parseMaybeJson(row.channels);
const dateOf = (row) => String(row.date || row.targetDate || row.report_date || (statusOf(row).nocodb && statusOf(row).nocodb.reportDate) || '').slice(0, 10) || 'unknown';
const candidateOf = (row) => candidateByDate[dateOf(row)] || {};

const hasHardFailure = (row) => {
  const nocodb = nocodbOf(row);
  const sheets = sheetsOf(row);
  return row.ok === false
    || !!row.error
    || nocodb.ok === false
    || sheets.ok === false;
};
const hasUnresolvedCoupang = (row) => {
  const status = statusOf(row);
  const coupang = coupangOf(row);
  const severity = String(status.severity || row.severity || '').toUpperCase();
  const source = String(coupang.source || row.coupangSource || '').toLowerCase();
  const error = String(coupang.error || '').trim();
  return severity === 'ERROR'
    || coupang.needsBackfill === true
    || source === 'pending_backfill'
    || (!!error && (source.includes('existing') || source.includes('pending') || !!status.coupang));
};
const isResolved = (row) => !hasHardFailure(row) && !hasUnresolvedCoupang(row);

const resolved = executed.filter(isResolved);
const hardFailed = executed.filter((row) => hasHardFailure(row));
const unresolved = executed.filter((row) => !hasHardFailure(row) && hasUnresolvedCoupang(row));
const okCount = resolved.length;
const unresolvedCount = unresolved.length;
const hardFailCount = hardFailed.length;
const failCount = unresolvedCount + hardFailCount;

const outcomeOf = (row) => {
  if (hasHardFailure(row)) return '실패';
  if (hasUnresolvedCoupang(row)) return '미해결';
  return '정정 완료';
};
const correctionOf = (row) => {
  const candidate = candidateOf(row);
  const channels = channelsOf(row);
  const beforeTotalKnown = hasNumber(candidate.beforeTotalRevenue);
  const beforeCoupangKnown = hasNumber(candidate.beforeCoupangRevenue);
  const afterTotal = num(row.total_revenue || row.totalRevenue || 0);
  const afterOrders = num(row.total_orders || row.totalOrders || 0);
  const afterCoupang = num(channels.coupang !== undefined ? channels.coupang : (row.coupang_revenue || row.coupangRevenue || 0));
  return {
    reason: candidate.reason || row.reason || '',
    beforeTotalKnown,
    beforeCoupangKnown,
    beforeTotal: num(candidate.beforeTotalRevenue),
    beforeOrders: num(candidate.beforeTotalOrders),
    beforeCoupang: num(candidate.beforeCoupangRevenue),
    beforeCoupangOrders: num(candidate.beforeCoupangOrders),
    afterTotal,
    afterOrders,
    afterCoupang,
    totalDiff: beforeTotalKnown ? afterTotal - num(candidate.beforeTotalRevenue) : null,
    coupangDiff: beforeCoupangKnown ? afterCoupang - num(candidate.beforeCoupangRevenue) : null,
  };
};
const detailOf = (row) => {
  const outcome = outcomeOf(row);
  const status = statusOf(row);
  const coupang = coupangOf(row);
  const nocodb = nocodbOf(row);
  if (outcome === '실패') return String(row.error || nocodb.error || sheetsOf(row).error || '실패').slice(0, 120);
  if (outcome === '미해결') {
    const source = coupang.source ? '쿠팡 ' + coupang.source : '쿠팡 미해결';
    const reason = coupang.note || coupang.error || status.severity || '재시도 필요';
    return (source + ' — ' + String(reason)).slice(0, 160);
  }
  return nocodb.action || '원장/시트 반영';
};
const correctionLines = (row) => {
  const c = correctionOf(row);
  const lines = [];
  if (c.beforeTotalKnown) {
    lines.push('  총매출 ' + fmt(c.beforeTotal) + ' → ' + fmt(c.afterTotal) + ' (' + signedFmt(c.totalDiff) + ')');
  } else {
    lines.push('  총매출 신규 반영 ' + fmt(c.afterTotal));
  }
  if (c.beforeCoupangKnown) {
    lines.push('  쿠팡윙 ' + fmt(c.beforeCoupang) + ' → ' + fmt(c.afterCoupang) + ' (' + signedFmt(c.coupangDiff) + ')');
  } else {
    lines.push('  쿠팡윙 신규 반영 ' + fmt(c.afterCoupang));
  }
  if (c.reason) lines.push('  감지 사유: ' + String(c.reason).slice(0, 80));
  return lines;
};

let message = '<b>[운영알림][F23B] 매출 백필 정정 알림</b>\n';
if (sheetReadError) message += 'Sheet 조회 경고: ' + String(sheetReadError).slice(0, 250) + '\n';
if (executed.length === 0) {
  message += '문제 없음: ' + (skipped[0] && skipped[0].reason ? skipped[0].reason : '최근 3일 백필 후보 없음');
} else {
  message += '매출 반영 문제 감지: ' + executed.length + '일\n';
  message += '정정 완료 ' + okCount + ' / 미해결 ' + unresolvedCount + ' / 실패 ' + hardFailCount + '\n';
  for (const row of executed.slice(0, 10)) {
    const date = dateOf(row);
    message += '\n- ' + date + ': ' + outcomeOf(row) + ' (' + detailOf(row) + ')\n';
    for (const line of correctionLines(row)) message += line + '\n';
  }
  if (unresolvedCount > 0) {
    message += '\n조치: 미해결 일자는 다음 19:30 자동 백필 대상에 계속 남습니다. 반복 403이면 쿠팡 API/IP/허용시간을 수동 확인하세요.\n';
  }
}
// 문제 후보가 없으면 Telegram 운영알림을 보내지 않는다. 문제 감지/정정/미해결/실패/Sheet 조회 경고만 알림 대상이다.
const shouldNotify = executed.length > 0 || failCount > 0 || !!sheetReadError || (skipped[0] && String(skipped[0].reason || '').includes('실패'));
const corrections = executed.map((row) => ({ date: dateOf(row), outcome: outcomeOf(row), ...correctionOf(row) }));
return [{ json: { message, shouldNotify, isWebhook, executedCount: executed.length, resolvedCount: okCount, okCount, unresolvedCount, hardFailCount, failCount, skippedCount: skipped.length, skippedReason: skipped[0] && skipped[0].reason, sheetReadError, corrections } }];
